from machine import Pin, PWM
from utime import sleep

ride_pulse = Pin(4, Pin.OUT, value=0)
ride_direction = Pin(5, Pin.OUT, value=1)
ride_motor = PWM(ride_pulse)
FRAME_USTEPS = 6400

frame1_pulse = Pin(1, Pin.OUT, value=0)
frame1_direction = Pin(0, Pin.OUT, value=0)
frame1_motor = PWM(frame1_pulse)

frame2_pulse = Pin(3, Pin.OUT, value=0)
frame2_direction = Pin(2, Pin.OUT, value=0)
frame2_motor = PWM(frame2_pulse)


frame_enable = Pin(2, Pin.OUT, value=1)
frame_enable = Pin(2, Pin.OUT, value=1)
ride_enable = Pin(2, Pin.OUT, value=1)


def set_ride_speed(pwm:PWM, dir:Pin, speed:float):
    '''
    Sets the speed of the given PWM object using the globally defined microsteps

    Parameters
    ----------
    pwm : PWM
        The motor to control
    speed : float
        The speed in Hz.
    '''
    if speed < 0:
        dir.value(1)
    else:
        dir.value(0)

    pwm.deinit()
    frequency = speed*FRAME_USTEPS
    if abs(frequency) >= 10:
        pwm.init(freq=int(abs(frequency)), duty_u16=2**16//2)

